import { useEffect, useState, useCallback } from "react";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {
  const [role, setRole] = useState(null);
  const [bugs, setBugs] = useState([]);
  const [loading, setLoading] = useState(true);

  const token = localStorage.getItem("token");

  // 🔥 Fetch company bugs
  const fetchCompanyBugs = useCallback(() => {
    if (!token) return;

    setLoading(true);

    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data)) setBugs(data);
        else if (Array.isArray(data.bugs)) setBugs(data.bugs);
        else setBugs([]);
      })
      .catch((err) => {
        console.error("FETCH COMPANY BUGS ERROR:", err);
        setBugs([]);
      })
      .finally(() => setLoading(false));
  }, [token]);

  useEffect(() => {
    const storedRole = localStorage.getItem("role");

    // 🔒 Auth guard
    if (!token) {
      window.location.href = "/";
      return;
    }

    // 🔒 Role guard
    if (storedRole !== "company" && storedRole !== "admin") {
      window.location.href = "/hacker";
      return;
    }

    setRole(storedRole);
    fetchCompanyBugs();
  }, [fetchCompanyBugs, token]);

  // ⏳ Prevent blank render
  if (!role) return null;

  // ✅ Approve / Reject
  const validateBug = async (bugId, status) => {
    const severity =
      status === "approved"
        ? prompt("Enter severity (low / medium / high / critical):", "low")
        : null;

    const reward =
      status === "approved"
        ? Number(prompt("Enter reward amount:", "0"))
        : 0;

    if (status === "approved" && !severity) return;

    try {
      await fetch(
        `http://localhost:5000/api/bugs/validate/${bugId}`,
        {
          method: "PATCH",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({
            status,
            severity,
            reward,
          }),
        }
      );

      fetchCompanyBugs(); // 🔁 Refresh after action
    } catch (err) {
      console.error("VALIDATION ERROR:", err);
    }
  };

  return (
    <div className="company-dashboard">
      <header className="company-header">
        <h1>🏢 Company Dashboard</h1>
        <button
          className="logout-btn"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </header>

      {loading ? (
        <p className="muted">Loading bugs...</p>
      ) : bugs.length === 0 ? (
        <p className="muted">No bugs assigned to your company.</p>
      ) : (
        <table className="bugs-table">
          <thead>
            <tr>
              <th>Title</th>
              <th>Severity</th>
              <th>Status</th>
              <th>Reward</th>
              <th>Actions</th>
            </tr>
          </thead>

          <tbody>
            {bugs.map((bug) => (
              <tr key={bug._id}>
                <td>{bug.title}</td>
                <td className={`severity ${bug.severity}`}>
                  {bug.severity}
                </td>
                <td className={`status ${bug.status}`}>
                  {bug.status}
                </td>
                <td>₹{bug.reward || 0}</td>
                <td>
                  {bug.status === "submitted" ? (
                    <>
                      <button
                        className="approve"
                        onClick={() =>
                          validateBug(bug._id, "approved")
                        }
                      >
                        Approve
                      </button>
                      <button
                        className="reject"
                        onClick={() =>
                          validateBug(bug._id, "rejected")
                        }
                      >
                        Reject
                      </button>
                    </>
                  ) : (
                    <span className="done">Done</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}
